import{_ as a,c as s,o as t,b as i}from"./app.e8e78a69.js";const b='{"title":"\u0428\u0430\u0442\u0442\u0440\u0438\u043C\u0448\u0430\u0442\u0442\u0430\u0442\u0442\u0432\u0430\u0441\u0430\u043D\u0434\u043E\u0445\u0430","description":"","frontmatter":{"title":"\u0428\u0430\u0442\u0442\u0440\u0438\u043C\u0448\u0430\u0442\u0442\u0430\u0442\u0442\u0432\u0430\u0441\u0430\u043D\u0434\u043E\u0445\u0430","subtitle":"\u0421\u043E\u0431\u0440\u0430\u043D\u0438\u0435 \u0442\u0440\u0438\u0434\u0446\u0430\u0442\u0438 \u0448\u0435\u0441\u0442\u0438 \u0442\u0430\u0442\u0442\u0432","sans":"\u0937\u091F\u094D\u0924\u094D\u0930\u093F\u0902\u0936\u0924\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u0938\u0928\u094D\u0926\u094B\u0939","trans":"\u1E62a\u1E6Dtri\u1E41\u015Battattvasandoha","tags":"text","date":"2021-05-05T00:00:00.000Z"},"headers":[],"relativePath":"texts/shattrimshattattva/index.md"}',r={},p=i('<p>Am\u1E5Bt\u0101nandan\u0101tha, 12 \u0432\u0435\u043A \u043D.\u044D. \u041F\u0435\u0440\u0435\u0432\u043E\u0434 \u0441 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0430 \u0415\u0440\u0447\u0435\u043D\u043A\u043E\u0432\u0430 \u041E. \u041D.</p><div class="stanza"><a href="#s1" id="s1" class="num">1</a><p class="sans">\u092F\u0926\u092F\u092E\u0928\u0941\u0924\u094D\u0924\u0930\u092E\u0942\u0930\u094D\u0924\u093F\u0930\u094D\u0928\u091C\u0947\u091A\u094D\u091B\u092F\u093E\u0916\u093F\u0932\u092E\u093F\u0926\u0902 \u091C\u0917\u0924\u094D\u0938\u094D\u0930\u0937\u094D\u091F\u0941\u092E\u094D\u0964<br> \u092A\u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u0938 \u0938\u094D\u092A\u0928\u094D\u0926\u0903 \u092A\u094D\u0930\u0925\u092E\u0903 \u0936\u093F\u0935\u0924\u0924\u094D\u0924\u094D\u0935\u092E\u0941\u091A\u094D\u092F\u0924\u0947 \u0924\u091C\u094D\u091C\u094D\u091E\u0948\u0903\u0965\u0967\u0965</p><p class="trans">Yadayamanuttaram\u016Brtirnijecchay\u0101khilamida\u1E41 jagatsra\u1E63\u1E6Dum\u0964<br> Paspande sa spanda\u1E6D prathama\u1E6D \u015Bivatattvamucyate tajj\xF1ai\u1E6D\u09651\u0965</p><p>\u041D\u0430\u0438\u0432\u044B\u0441\u0448\u0438\u0439 \u041E\u0431\u0440\u0430\u0437 (\u0410\u0431\u0441\u043E\u043B\u044E\u0442\u0430, \u0410\u043D\u0443\u0442\u0442\u0430\u0440\u0430 \u043C\u0443\u0440\u0442\u0438), \u0442\u0432\u043E\u0440\u044F\u0449\u0438\u0439 \u0421\u0432\u043E\u0435\u0439 \u0412\u043E\u043B\u0435\u0439 \u0432\u0441\u044E \u044D\u0442\u0443 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E - \u043F\u0443\u043B\u044C\u0441\u0438\u0440\u0443\u044E\u0449\u0430\u044F \u0441\u043F\u0430\u043D\u0434\u0430, \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0437\u043D\u0430\u044E\u0449\u0438\u043C\u0438 \u043F\u0435\u0440\u0432\u043E\u0439, \u0428\u0438\u0432\u0430 \u0442\u0430\u0442\u0442\u0432\u043E\u0439.</p></div><div class="stanza"><a href="#s2" id="s2" class="num">2</a><p class="sans">\u0907\u091A\u094D\u091B\u093E \u0938\u0948\u0935 \u0938\u094D\u0935\u091A\u094D\u091B\u093E \u0938\u0928\u094D\u0924\u0924\u0938\u092E\u0935\u093E\u092F\u093F\u0928\u0940 \u0938\u0924\u0940 \u0936\u0915\u094D\u0924\u093F\u0903\u0964<br> \u0938\u091A\u0930\u093E\u091A\u0930\u0938\u094D\u092F \u091C\u0917\u0924\u094B \u092C\u0940\u091C\u0902 \u0928\u093F\u0916\u093F\u0932\u0938\u094D\u092F \u0928\u093F\u091C\u0928\u093F\u0932\u0940\u0928\u0938\u094D\u092F\u0965\u0968\u0965</p><p class="trans">Icch\u0101 saiva svacch\u0101 santatasamav\u0101yin\u012B sati \u015Bakti\u1E25\u0964<br> Sacar\u0101carasya jagato b\u012Bja\u1E41 nikhilasya nijanil\u012Bnasya\u09652\u0965</p><p>\u0421\u0443\u0449\u0430\u044F \u0438\u0447\u0447\u0445\u0430 \u0428\u0430\u043A\u0442\u0438 \u2013 (\u0415\u0433\u043E) \u0432\u0435\u0447\u043D\u0430\u044F \u043D\u0435\u043E\u0442\u044A\u0435\u043C\u043B\u0435\u043C\u0430\u044F \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0412\u043E\u043B\u044F. (\u041E\u043D\u0430) \u2013 \u0441\u0435\u043C\u044F \u0432\u0441\u0435\u0439 \u0434\u0432\u0438\u0436\u0443\u0449\u0435\u0439\u0441\u044F \u0438 \u043D\u0435\u043F\u043E\u0434\u0432\u0438\u0436\u043D\u043E\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u0438 \u0415\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438.</p></div><div class="stanza"><a href="#s3" id="s3" class="num">3</a><p class="sans">\u0938\u094D\u0935\u0947\u091A\u094D\u091B\u093E\u0936\u0915\u094D\u0924\u094D\u092F\u0941\u0926\u094D\u0917\u0940\u0930\u094D\u0923\u0902 \u091C\u0917\u0926\u093E\u0924\u094D\u092E\u0924\u092F\u093E \u0938\u092E\u093E\u091A\u094D\u091B\u093E\u0926\u094D\u092F\u0964<br> \u0928\u093F\u0935\u0938\u0928\u094D \u0938 \u090F\u0935 \u0928\u093F\u0916\u093F\u0932\u093E\u0928\u0941\u0917\u094D\u0930\u0939\u0928\u093F\u0930\u0924\u0903 \u0938\u0926\u093E\u0936\u093F\u0935\u094B\u093D\u092D\u093F\u0939\u093F\u0924\u0903\u0965\u0969\u0965</p><p class="trans">Svecch\u0101\u015Baktyudg\u012Br\u1E47a\u1E41 jagad\u0101tmatay\u0101 sam\u0101cch\u0101dya\u0964<br> Nivasan sa eva nikhil\u0101nugrahanirata\u1E25 sad\u0101\u015Bivo&#39;bhihita\u1E25\u09653\u0965</p><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0421\u0432\u043E\u0435\u0439 \u0438\u0447\u0447\u0445\u0430 \u0448\u0430\u043A\u0442\u0438, \u043F\u0435\u0440\u0435\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 (\u0434\u0436\u0430\u0433\u0430\u0442\u0434\u0430\u0442\u043C\u0430), \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0421\u0430\u0434\u0430\u0448\u0438\u0432\u0430, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0439 \u0432\u0441\u044E \u043C\u0438\u043B\u043E\u0441\u0442\u044C.</p></div><div class="stanza"><a href="#s4" id="s4" class="num">4</a><p class="sans">\u0935\u093F\u0936\u094D\u0935\u0902 \u092A\u0936\u094D\u091A\u093E\u0924\u094D\u092A\u0936\u094D\u092F\u0928\u093F\u0926\u0928\u094D\u0924\u092F\u093E \u0928\u093F\u0916\u093F\u0932\u092E\u0940\u0936\u094D\u0935\u0930\u094B \u091C\u093E\u0924\u0903\u0964<br> \u0938\u093E \u092D\u0935\u0924\u093F \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E \u092F\u0947\u0926\u0928\u094D\u0924\u093E\u0939\u0928\u094D\u0924\u092F\u094B\u0930\u092D\u0947\u0926\u092E\u0924\u093F\u0903\u0965\u096A\u0965</p><p class="trans">Vi\u015Bva\u1E41 pa\xF1c\u0101tpa\u015Byanidantay\u0101 nikhilam\u012B\u015Bvaro j\u0101ta\u1E25\u0964<br> S\u0101 bhavati \u015Buddhavidy\u0101 yedant\u0101hantayorabhedamati\u1E25\u09654\u0965</p><p>\u0417\u0430\u0442\u0435\u043C \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0418\u0448\u0432\u0430\u0440\u0430, \u0437\u0440\u044F\u0449\u0438\u0439 \u0432\u0441\u044E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \xAB\u044D\u0442\u043E\u0433\u043E\xBB (\u0438\u0434\u0430\u043D\u0442\u0430). (\u0417\u0430\u0442\u0435\u043C) \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0448\u0443\u0434\u0434\u0445\u0430 \u0432\u0438\u0434\u044C\u044F, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \xAB\u042F\xBB \u0438 \xAB\u0422\u043E\xBB - \u043D\u0435\u0440\u0430\u0437\u0434\u0435\u043B\u044C\u043D\u044B.</p></div><div class="stanza"><a href="#s5" id="s5" class="num">5</a><p class="sans">\u092E\u093E\u092F\u093E \u0935\u093F\u092D\u0947\u0926\u092C\u0941\u0926\u094D\u0927\u093F\u0930\u094D\u0928\u093F\u091C\u093E\u0902\u0936\u091C\u093E\u0924\u0947\u0937\u0941 \u0928\u093F\u0916\u093F\u0932\u091C\u0940\u0935\u0947\u0937\u0941\u0964<br> \u0928\u093F\u0924\u094D\u092F\u0902 \u0924\u0938\u094D\u092F \u0928\u093F\u0930\u0919\u094D\u0915\u0941\u0936\u0935\u093F\u092D\u0935\u0902 \u0935\u0947\u0932\u0947\u0935 \u0935\u093E\u0930\u093F\u0927\u0947 \u0930\u0941\u0928\u094D\u0927\u0947\u0965\u096B\u0965</p><p class="trans">M\u0101y\u0101 vibhedabuddhirnij\u0101\u1E41\u015Baj\u0101te\u1E63u nikhilaj\u012Bve\u1E63u\u0964<br> Nitya\u1E41 tasya nira\u1E45ku\u015Bavibhava\u1E41 veleva v\u0101ridhe rundhe\u09655\u0965</p><p>\u0415\u0433\u043E (\u041F\u0430\u0440\u0430\u043C\u0435\u0448\u0432\u0430\u0440\u044B) \u0420\u0430\u0437\u0443\u043C (\u0431\u0443\u0434\u0434\u0445\u0438), \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0435\u0441\u0442\u044C \u041C\u0430\u0439\u0430 (\u0442\u0430\u0442\u0442\u0432\u0430) \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430 \u0447\u0430\u0441\u0442\u0438 \u0441\u0440\u0435\u0434\u0438 \u0434\u0436\u0438\u0432, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0445\u0441\u044F \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C\u0438 \u0438\u043C \u0447\u0430\u0441\u0442\u044F\u043C\u0438 \u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u0435\u0442 \u0438\u0445, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0431\u0435\u0440\u0435\u0433\u0443, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0449\u0435\u043C\u0443 \u043E\u043A\u0435\u0430\u043D. \u041D\u043E, \u0434\u0430\u0436\u0435 \u0431\u0443\u0434\u0443\u0447\u0438 (\u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u043D\u044B\u043C) \u0432 \u043D\u0435\u0447\u0438\u0441\u0442\u044B\u0439 \u043F\u043E\u0440\u044F\u0434\u043E\u043A, \u041F\u0430\u0440\u0430\u043C\u0435\u0448\u0432\u0430\u0440\u0430 \u0432\u0435\u0447\u043D\u043E (\u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u043E\u0431\u043B\u0430\u0434\u0430\u0442\u0435\u043B\u0435\u043C) \u0421\u0432\u043E\u0435\u0433\u043E \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0433\u043E \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430.</p></div><div class="stanza"><a href="#s6" id="s6" class="num">6</a><p class="sans">\u0938 \u0924\u092F\u093E \u092A\u0930\u093F\u092E\u093F\u0924\u092E\u0942\u0930\u094D\u0924\u093F\u0903 \u0938\u0919\u094D\u0915\u0941\u091A\u093F\u0924\u0938\u092E\u0938\u094D\u0924\u0936\u0915\u094D\u0924\u093F\u0930\u0947\u0937 \u092A\u0941\u092E\u093E\u0928\u094D\u0964<br> \u0930\u0935\u093F\u0930\u093F\u0935 \u0938\u0928\u094D\u0927\u094D\u092F\u093E\u0930\u0915\u094D\u0924\u0903 \u0938\u0902\u0939\u0943\u0924\u0936\u0915\u094D\u0924\u093F\u0903 \u0938\u094D\u0935\u092D\u093E\u0938\u0928\u0947\u093D\u092A\u094D\u092F\u092A\u091F\u0941\u0903\u0965\u096C\u0965</p><p class="trans">Sa tay\u0101 parimitam\u016Brti\u1E25 sa\u1E45kucitasamasta\u015Baktire\u1E63a pum\u0101n\u0964<br> Raviriva sandhy\u0101rakta\u1E25 sa\u1E41h\u1E5Bta\u015Bakti\u1E25 svabh\u0101sane&#39;pyapa\u1E6Du\u1E25\u09656\u0965</p><p>\u041F\u043E\u0434 \u0432\u043B\u0438\u044F\u043D\u0438\u0435\u043C \u044D\u0442\u043E\u0439 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0449\u0435\u0439 \u0428\u0430\u043A\u0442\u0438 \u041E\u043D (\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F) \u043F\u0443\u0440\u0443\u0448\u0435\u0439(\u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u043C \u0436\u0438\u0432\u044B\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u043C), \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u043A\u0440\u0430\u0441\u043D\u043E\u043C\u0443 \u043D\u0435 \u0436\u0433\u0443\u0447\u0435\u043C\u0443 \u0441\u043E\u043B\u043D\u0446\u0443, \u0447\u044C\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E \u0437\u0430\u0431\u0438\u0440\u0430\u0435\u0442 \u0437\u0430\u0440\u044F.</p></div><div class="stanza"><a href="#s7" id="s7" class="num">7</a><p class="sans">\u0938\u092E\u094D\u092A\u0942\u0930\u094D\u0923\u0915\u0930\u094D\u0924\u0943\u0924\u093E\u0926\u094D\u092F\u093E \u092C\u0939\u094D\u0935\u094D\u092F\u0903 \u0938\u0928\u094D\u0924\u094D\u092F\u0938\u094D\u092F \u0936\u0915\u094D\u0924\u092F\u0938\u094D\u0924\u0938\u094D\u092F\u0964<br> \u0938\u0919\u094D\u0915\u094B\u091A\u093E\u0924\u094D\u0938\u0919\u094D\u0915\u0941\u091A\u093F\u0924\u093E\u0903 \u0915\u0932\u093E\u0926\u093F\u0930\u0942\u092A\u0947\u0923 \u0930\u0942\u0922\u092F\u0928\u094D\u0924\u094D\u092F\u0947\u0935\u092E\u094D\u0965\u096D\u0965</p><p class="trans">Samp\u016Br\u1E47akart\u1E5Bt\u0101dy\u0101 bahvya\u1E25 santyasya \u015Baktayastasya\u0964<br> Sa\u1E45koc\u0101tsa\u1E45kucit\u0101\u1E25 kal\u0101dir\u016Bpe\u1E47a r\u016B\u1E0Dhayantyevam\u09657\u0965</p><p>\u041C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u043F\u0440\u0438\u0441\u0443\u0449\u0438\u0445 \u0435\u043C\u0443 \u0428\u0430\u043A\u0442\u0438 \u043F\u043E\u043B\u043D\u043E\u0442\u044B, \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E, \u0431\u0443\u0434\u0443\u0447\u0438 \u0441\u043E\u0431\u0440\u0430\u043D\u043D\u044B\u043C\u0438, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0442 \u0435\u0433\u043E \u0432 \u0444\u043E\u0440\u043C\u0435 \u043A\u0430\u043B\u0410 (\u0442\u0430\u0442\u0442\u0432\u044B) \u0438 \u0442.\u0434.</p></div><div class="stanza"><a href="#s8" id="s8" class="num">8</a><p class="sans">\u0924\u0924\u094D\u0938\u0930\u094D\u0935\u0915\u0930\u094D\u0924\u0943\u0924\u093E \u0938\u093E \u0938\u0919\u094D\u0915\u0941\u091A\u093F\u0924\u093E \u0915\u0924\u093F\u092A\u092F\u093E\u0930\u094D\u0925\u092E\u093E\u0924\u094D\u0930\u092A\u0930\u093E\u0964<br> \u0915\u093F\u091E\u094D\u091A\u093F\u0924\u094D\u0915\u0930\u094D\u0924\u093E\u0930\u092E\u092E\u0941\u0902 \u0915\u0932\u092F\u0928\u094D\u0924\u0940 \u0915\u0940\u0930\u094D\u0924\u094D\u092F\u0924\u0947 \u0915\u0932\u093E \u0928\u093E\u092E\u0965\u096E\u0965</p><p class="trans">Tatsarvakart\u1E5Bt\u0101 s\u0101 sa\u1E45kucit\u0101 katipay\u0101rtham\u0101trapar\u0101\u0964<br> Ki\xF1citkart\u0101ramamu\u1E41 kalayant\u012B k\u012Brtyate kal\u0101 n\u0101ma\u09658\u0965</p><p>\u041E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0449\u0430\u044F (\u0428\u0430\u043A\u0442\u0438), \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043A\u0430\u043B\u0410 (\u0422\u0430\u0442\u0442\u0432\u043E\u0439). \u041E\u043D\u0430 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u0435\u0442 \u0415\u0433\u043E \u0432\u0441\u0435\u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0438 \u043F\u043E\u0431\u0443\u0436\u0434\u0430\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u0443\u044E \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C.</p></div><div class="stanza"><a href="#s9" id="s9" class="num">9</a><p class="sans">\u0938\u0930\u094D\u0935\u091C\u094D\u091E\u0924\u093E\u0938\u094D\u092F \u0936\u0915\u094D\u0924\u093F\u0903 \u092A\u0930\u093F\u092E\u093F\u0924\u0924\u0928\u0941\u0930\u0932\u094D\u092A\u0935\u0947\u0926\u094D\u092F\u092E\u093E\u0924\u094D\u0930\u092A\u0930\u093E\u0964<br> \u091C\u094D\u091E\u093E\u0928\u092E\u0941\u0924\u094D\u092A\u093E\u0926\u092F\u0928\u094D\u0924\u0940 \u0935\u093F\u0926\u094D\u092F\u0947\u0924\u093F \u0928\u093F\u0917\u0926\u094D\u092F\u0924\u0947 \u092C\u0941\u0927\u0948\u0930\u093E\u0926\u094D\u092F\u0948\u0903\u0965\u096F\u0965</p><p class="trans">Sarvaj\xF1at\u0101sya \u015Bakti\u1E25 parimitatanuralpavedyam\u0101trapar\u0101\u0964<br> J\xF1\u0101namutp\u0101dayant\u012B vidyeti nigadyate budhair\u0101dyai\u1E25\u09659\u0965</p><p>\u0428\u0430\u043A\u0442\u0438, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0449\u0430\u044F \u0415\u0433\u043E \u0432\u0441\u0435\u0437\u043D\u0430\u043D\u0438\u0435, \u0437\u043D\u0430\u043D\u0438\u0435\u043C \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u043C\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u043A \u0442\u0435\u043B\u0443, \u0438 \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u044E\u0449\u0430\u044F (\u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0435) \u0437\u043D\u0430\u043D\u0438\u0435, \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043C\u0443\u0434\u0440\u044B\u043C\u0438 \u0432\u0438\u0434\u044C\u044F \u0442\u0430\u0442\u0442\u0432\u043E\u0439.</p></div><div class="stanza"><a href="#s10" id="s10" class="num">10</a><p class="sans">\u0928\u093F\u0924\u094D\u092F\u092A\u0930\u093F\u092A\u0942\u0930\u094D\u0923\u0924\u0943\u092A\u094D\u0924\u093F\u0903 \u0936\u0915\u094D\u0924\u093F\u0938\u094D\u0924\u0938\u094D\u092F\u0948\u0935 \u092A\u0930\u093F\u092E\u093F\u0924\u093E \u0924\u0941 \u0938\u0924\u0940\u0964<br> \u092D\u094B\u0917\u0947\u0937\u0941 \u0930\u091E\u094D\u091C\u092F\u0928\u094D\u0924\u0940 \u0938\u0924\u0924\u092E\u092E\u0941\u0902 \u0930\u093E\u0917\u0924\u0924\u094D\u0924\u094D\u0935\u0924\u093E\u0902 \u092F\u093E\u0924\u093E\u0965\u0967\u0966\u0965</p><p class="trans">Nityaparip\u016Br\u1E47at\u1E5Bpti\u1E25 \u015Baktistasyaiva parimit\u0101 tu sat\u012B\u0964<br> Bhoge\u1E63u ra\xF1jayant\u012B satatamamu\u1E41 r\u0101gatattvat\u0101\u1E41 y\u0101t\u0101\u096510\u0965</p><p>\u0428\u0430\u043A\u0442\u0438, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0449\u0430\u044F \u0415\u0433\u043E \u0432\u0435\u0447\u043D\u043E\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0435 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435, \u043D\u043E \u044F\u0432\u043B\u044F\u044E\u0449\u0430\u044F\u0441\u044F (\u0415\u0433\u043E) \u0446\u0435\u043B\u043E\u043C\u0443\u0434\u0440\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u043F\u0440\u0443\u0433\u043E\u0439, \u0446\u0430\u0440\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0439 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0432 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u0445 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0435\u0441\u0442\u044C \u0440\u0430\u0433\u0430 \u0442\u0430\u0442\u0442\u0432\u0430 - \u0415\u0433\u043E \u0441\u0443\u043F\u0440\u0443\u0433\u0430.</p></div><div class="stanza"><a href="#s11" id="s11" class="num">11</a><p class="sans">\u0938\u093E \u0928\u093F\u0924\u094D\u092F\u0924\u093E\u0938\u094D\u092F \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u0928\u093F\u0915\u0943\u0937\u094D\u092F \u0928\u093F\u0927\u0928\u094B\u0926\u092F\u092A\u094D\u0930\u0926\u093E\u0928\u0947\u0928\u0964<br> \u0928\u093F\u092F\u0924\u092A\u0930\u093F\u091A\u094D\u091B\u0947\u0926\u0915\u0930\u0940 \u0915\u0962\u092A\u094D\u0924\u093E \u0938\u094D\u092F\u093E\u0924\u094D\u0915\u093E\u0932\u0924\u0924\u094D\u0924\u094D\u0935\u0930\u0942\u092A\u0947\u0923\u0965\u0967\u0967\u0965</p><p class="trans">S\u0101 nityat\u0101sya \u015Baktirnik\u1E5B\u1E63ya nidhanodayaprad\u0101nena\u0964<br> Niyataparicchedakar\u012B k\u1E37pt\u0101 sy\u0101tk\u0101latattvar\u016Bpe\u1E47a\u096511\u0965</p><p>\u0428\u0430\u043A\u0442\u0438, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0449\u0430\u044F \u0415\u0433\u043E \u0432\u0435\u0447\u043D\u043E\u0441\u0442\u044C, \u043D\u0430\u0434\u0435\u043B\u044F\u044F \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C \u0441\u043C\u0435\u0440\u0442\u0438 \u0438 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043A\u0410\u043B\u0430 \u0442\u0430\u0442\u0442\u0432\u044B, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u044E\u0449\u0435\u0439 (\u0415\u0433\u043E) \u043E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0434\u0440\u043E\u0431\u043B\u0435\u043D\u0438\u0435.</p></div><div class="stanza"><a href="#s12" id="s12" class="num">12</a><p class="sans">\u092F\u093E\u0938\u094D\u092F \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u0924\u093E\u0916\u094D\u092F\u093E \u0936\u0915\u094D\u0924\u093F\u0903 \u0938\u0919\u094D\u0915\u094B\u091A\u0936\u093E\u0932\u093F\u0928\u0940 \u0938\u0948\u0935\u0964<br> \u0915\u0943\u0924\u094D\u092F\u093E\u0915\u0943\u0924\u094D\u092F\u0947\u0937\u094D\u0935\u0935\u0936\u0902 \u0928\u093F\u092F\u0924\u092E\u092E\u0941\u0902 \u0928\u093F\u092F\u092E\u092F\u0928\u094D\u0924\u094D\u092F\u092D\u0942\u0928\u094D\u0928\u093F\u092F\u0924\u093F\u0903\u0965\u0967\u0968\u0965</p><p class="trans">Y\u0101sya svatantrat\u0101khy\u0101 \u015Bakti\u1E25 sa\u1E45koca\u015B\u0101lin\u012B saiva\u0964<br> K\u1E5Bty\u0101k\u1E5Btye\u1E63vava\u015Ba\u1E41 niyatamamu\u1E41 niyamayantyabh\u016Bnniyati\u1E25\u096512\u0965</p><p>\u0415\u0433\u043E \u0428\u0430\u043A\u0442\u0438, \u0438\u043C\u0435\u043D\u0443\u0435\u043C\u0430\u044F \u0421\u0430\u043C\u043E\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E\u0441\u0442\u044C (\u0441\u0432\u0430\u0442\u0430\u043D\u0442\u0440\u0430\u0442\u0430) \u043F\u043E\u0434 \u0432\u043B\u0438\u044F\u043D\u0438\u0435\u043C \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u044C, \u043E\u043D\u0430 \u0436\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044F \u0441\u0435\u0431\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0438 \u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435\u043C, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043D\u0438\u044F\u0442\u0438 \u0442\u0430\u0442\u0442\u0432\u043E\u0439.</p></div><div class="stanza"><a href="#s13" id="s13" class="num">13</a><p class="sans">\u0907\u091A\u094D\u091B\u093E\u0926\u093F\u0924\u094D\u0930\u093F\u0938\u092E\u0937\u094D\u091F\u093F\u0903 \u0936\u0915\u094D\u0924\u093F\u0903 \u0936\u093E\u0928\u094D\u0924\u093E\u0938\u094D\u092F \u0938\u0919\u094D\u0915\u0941\u091A\u0926\u094D\u0930\u0942\u092A\u093E\u0964<br> \u0938\u0919\u094D\u0915\u0932\u093F\u0924\u0947\u091A\u094D\u091B\u093E\u0926\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u0938\u0924\u094D\u0924\u094D\u0935\u093E\u0926\u093F\u0915\u0938\u093E\u092E\u094D\u092F\u0930\u0942\u092A\u093F\u0923\u0940 \u0924\u0941 \u0938\u0924\u0940\u0965\u0967\u0969\u0965</p><p class="trans">Icch\u0101ditrisama\u1E63\u1E6Di\u1E25 \u015Bakti\u1E25 \u015B\u0101nt\u0101sya sa\u1E45kucadr\u016Bp\u0101\u0964<br> Sa\u1E45kalitecch\u0101dy\u0101tmakasattv\u0101dikas\u0101myar\u016Bpi\u1E47\u012B tu sat\u012B\u096513\u0965</p><p>\u0421\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u0442\u0440\u0435\u0445 \u0448\u0430\u043A\u0442\u0438, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0438\u0447\u0447\u0445\u0438 \u0435\u0441\u0442\u044C \u0444\u043E\u0440\u043C\u0430 \u041F\u043E\u043A\u043E\u044F. \u041E\u043D \u0435\u0441\u0442\u044C \u0441\u0443\u0449\u0435\u0435 \u0440\u0430\u0432\u043D\u043E\u0432\u0435\u0441\u0438\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437 \u0412\u043E\u043B\u0438 \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E, \u0441\u0430\u0442\u0442\u0432\u044B \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 (\u043A\u0430\u0447\u0435\u0441\u0442\u0432).</p></div><div class="stanza"><a href="#s14" id="s14" class="num">14</a><p class="sans">\u092C\u0941\u0926\u094D\u0927\u094D\u092F\u093E\u0926\u093F\u0938\u093E\u092E\u0930\u0938\u094D\u092F\u0938\u094D\u0935\u0930\u0942\u092A\u091A\u093F\u0924\u094D\u0924\u093E\u0924\u094D\u092E\u093F\u0915\u093E \u092E\u0924\u093E \u092A\u094D\u0930\u0915\u0943\u0924\u093F\u0903\u0964<br> \u0907\u091A\u094D\u091B\u093E\u0938\u094D\u092F \u0930\u091C\u094B\u0930\u0942\u092A\u093E\u0939\u0919\u094D\u0915\u0943\u0924\u093F\u0930\u093E\u0938\u0940\u0926\u0939\u092E\u094D\u092A\u094D\u0930\u0924\u0940\u0924\u093F\u0915\u0930\u0940\u0965\u0967\u096A\u0965</p><p class="trans">Buddhy\u0101dis\u0101marasyasvar\u016Bpacitt\u0101tmik\u0101 mat\u0101 prak\u1E5Bti\u1E25\u0964<br> Icch\u0101sya rajor\u016Bp\u0101ha\u1E45k\u1E5Btir\u0101s\u012Bdahamprat\u012Btikar\u012B\u096514\u0965</p><p>\u0421\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u0431\u0443\u0434\u0434\u0445\u0438 \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E, \u0447\u044C\u044F \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u0430\u044F \u0444\u043E\u0440\u043C\u0430 \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0438\u0437 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F - \u0435\u0441\u0442\u044C \u043F\u0440\u0430\u043A\u0440\u0438\u0442\u0438. \u0418\u0437 \u0438\u0447\u0447\u0445\u0438, \u0432 \u043E\u0431\u0440\u0430\u0437\u0435 \u0440\u0430\u0434\u0436\u0430\u0441\u0430, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u044D\u0433\u043E, \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u044E\u0449\u0435\u0435 \u0447\u0443\u0432\u0441\u0442\u0432\u043E \xAB\u044F\xBB.</p></div><div class="stanza"><a href="#s15" id="s15" class="num">15</a><p class="sans">\u091C\u094D\u091E\u093E\u0928\u093E\u092A\u093F \u0938\u0924\u094D\u0924\u094D\u0935\u0930\u0942\u092A\u093E \u0928\u093F\u0930\u094D\u0923\u092F\u092C\u094B\u0927\u0938\u094D\u092F \u0915\u093E\u0930\u0923\u0902 \u092C\u0941\u0926\u094D\u0927\u093F\u0903\u0964<br> \u0924\u0938\u094D\u092F \u0915\u094D\u0930\u093F\u092F\u093E \u0924\u092E\u094B\u092E\u092F\u092E\u0942\u0930\u094D\u0924\u093F\u0930\u094D\u092E\u0928 \u0909\u091A\u094D\u092F\u0924\u0947 \u0935\u093F\u0915\u0932\u094D\u092A\u0915\u0930\u0940\u0965\u0967\u096B\u0965</p><p class="trans">J\xF1\u0101n\u0101pi sattvar\u016Bp\u0101 nir\u1E47ayabodhasya k\u0101ra\u1E47a\u1E41 buddhi\u1E25\u0964<br> Tasya kriy\u0101 tamomayam\u016Brtirmana ucyate vikalpakar\u012B\u096515\u0965</p><p>\u0417\u043D\u0430\u043D\u0438\u0435 \u0432 \u0444\u043E\u0440\u043C\u0435 \u0441\u0430\u0442\u0442\u0432\u044B, \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, - \u0435\u0441\u0442\u044C \u0440\u0430\u0437\u0443\u043C (\u0431\u0443\u0434\u0434\u0445\u0438). \u0415\u0433\u043E \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0432 \u0442\u0430\u043C\u0430\u0441\u0435 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0443\u043C\u043E\u043C (\u043C\u0430\u043D\u0430\u0441\u043E\u043C), \u0442\u0432\u043E\u0440\u044F\u0449\u0438\u043C \u043C\u044B\u0441\u043B\u0435\u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F (\u0432\u0438\u043A\u0430\u043B\u044C\u043F\u044B).</p></div><div class="stanza"><a href="#s16" id="s16" class="num">16</a><p class="sans">\u0935\u093E\u092E\u093E\u0926\u093F\u092A\u091E\u094D\u091A\u092D\u0947\u0926\u0903 \u0938 \u090F\u0935 \u0938\u0919\u094D\u0915\u0941\u091A\u093F\u0924\u0935\u093F\u0917\u094D\u0930\u0939\u094B \u0926\u0947\u0935\u0903\u0964<br> \u091C\u094D\u091E\u093E\u0928\u0915\u094D\u0930\u093F\u092F\u094B\u092A\u0930\u093E\u0917\u092A\u094D\u0930\u093E\u0927\u093E\u0928\u094D\u092F\u093E\u0926\u094D\u0935\u093F\u0935\u093F\u0927\u0935\u093F\u0937\u092F\u0930\u0942\u092A\u094B\u093D\u092D\u0942\u0924\u094D\u0965\u0967\u096C\u0965</p><p class="trans">V\u0101m\u0101dipa\xF1cabheda\u1E25 sa eva sa\u1E45kucitavigraho deva\u1E25\u0964<br> J\xF1\u0101nakriyopar\u0101gapr\u0101dh\u0101ny\u0101dvividhavi\u1E63ayar\u016Bpo&#39;bh\u016Bt\u096516\u0965</p><p>\u0414\u0435\u043B\u0435\u043D\u0438\u0435 \u043D\u0430 \u0412\u0430\u043C\u0443 \u0438 \u043F\u0440\u043E\u0447\u0438\u0445, \u0435\u0441\u0442\u044C \u0443\u043C\u0430\u043B\u0435\u043D\u043D\u044B\u0439 \u043E\u0431\u0440\u0430\u0437 \u0411\u043E\u0433\u0430. \u041E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0437\u043D\u0430\u043D\u0438\u0435\u043C, \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C, \u043E\u043A\u0440\u0430\u0448\u0438\u0432\u0430\u043D\u0438\u0435\u043C, \u043F\u0440\u0435\u0434\u0448\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C \u0444\u043E\u0440\u043C\u0435 \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432.</p></div><div class="stanza"><a href="#s17" id="s17" class="num">17</a><p class="sans">\u0936\u094D\u0930\u094B\u0924\u094D\u0930\u0902 \u091A\u0915\u094D\u0937\u0941\u0903 \u0938\u094D\u092A\u0930\u094D\u0936\u0928\u091C\u093F\u0939\u094D\u0935\u093E\u0918\u094D\u0930\u093E\u0923\u093E\u0928\u093F \u092C\u094B\u0927\u0915\u0930\u0923\u093E\u0928\u093F\u0964<br> \u0936\u092C\u094D\u0926\u0938\u094D\u092A\u0930\u094D\u0936\u094C \u0930\u0942\u092A\u0902 \u0930\u0938\u0917\u0928\u094D\u0927\u094C \u091A\u0947\u0924\u093F \u092D\u0942\u0924\u0938\u0942\u0915\u094D\u0937\u094D\u092E\u093E\u0923\u093F\u0965\u0967\u096D\u0965</p><p class="trans">\u015Arotra\u1E41 cak\u1E63u\u1E25 spar\u015Banajihv\u0101ghr\u0101\u1E47\u0101ni bodhakara\u1E47\u0101ni\u0964<br> \u015Aabdaspar\u015Bau r\u016Bpa\u1E41 rasagandhau ceti bh\u016Btas\u016Bk\u1E63m\u0101\u1E47i\u096517\u0965</p><p>\u0423\u0445\u043E, \u0433\u043B\u0430\u0437, \u043A\u043E\u0436\u0430, \u044F\u0437\u044B\u043A, \u043D\u043E\u0441 \u2013 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u0417\u0432\u0443\u043A, \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435, \u0444\u043E\u0440\u043C\u0430, \u0432\u043A\u0443\u0441, \u0437\u0430\u043F\u0430\u0445, - \u0442\u043E\u043D\u043A\u0438\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B.</p></div><div class="stanza"><a href="#s18" id="s18" class="num">18</a><p class="sans">\u0905\u092F\u092E\u0947\u0935\u093E\u0924\u093F\u0928\u093F\u0915\u0943\u0937\u094D\u091F\u094B \u091C\u093E\u0924\u094B \u092D\u0942\u0924\u093E\u0924\u094D\u092E\u0928\u093E\u092A\u093F \u092D\u0942\u0924\u0947\u0936\u0903\u0964<br> \u0917\u0917\u0928\u092E\u0928\u093F\u0932\u0936\u094D\u091A \u0924\u0947\u091C\u0903 \u0938\u0932\u093F\u0932\u0902 \u092D\u0942\u092E\u093F\u0936\u094D\u091A \u092A\u091E\u094D\u091A\u092D\u0942\u0924\u093E\u0928\u093F\u0965\u0967\u096E\u0965</p><p class="trans">Ayamev\u0101tinik\u1E5B\u1E63\u1E6Do j\u0101to bh\u016Bt\u0101tman\u0101pi bh\u016Bte\u015Ba\u1E25\u0964<br> Gaganamanila\u015Bca teja\u1E25 salila\u1E41 bh\u016Bmi\u015Bca pa\xF1cabh\u016Bt\u0101ni\u096518\u0965</p><p>\u041F\u043E\u0440\u043E\u0436\u0434\u0430\u044E\u0449\u0438\u0439 \u0438\u0445, \u043D\u043E \u043D\u0435\u0437\u0430\u0442\u0440\u043E\u043D\u0443\u0442\u044B\u0439 \u0438\u043C\u0438 \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u043D\u044B\u0439 \u0410\u0442\u043C\u0430\u043D (\u0411\u0445\u0443\u0442\u0430\u0442\u043C\u0430\u043D) \u2013 \u0435\u0441\u0442\u044C \u0432\u043B\u0430\u0434\u044B\u043A\u0430 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 \u0411\u0445\u0443\u0442\u0435\u0448\u0430. \u041F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E, \u0432\u043E\u0437\u0434\u0443\u0445, \u043E\u0433\u043E\u043D\u044C, \u0432\u043E\u0434\u0430 \u0438 \u0437\u0435\u043C\u043B\u044F \u2013 \u043F\u044F\u0442\u044C (\u0433\u0440\u0443\u0431\u044B\u0445) \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432.</p></div><div class="stanza"><a href="#s19" id="s19" class="num">19</a><p class="sans">\u0936\u094D\u0930\u094B\u0924\u094D\u0930\u093E\u0926\u093F\u0915\u0930\u0923\u0935\u0947\u0926\u094D\u092F\u093E\u0903 \u0936\u092C\u094D\u0926\u093E\u0926\u094D\u092F\u093E\u0938\u094D\u0924\u093E\u0928\u093F \u0935\u0947\u0926\u0915\u093E\u0928\u094D\u092F\u0947\u0937\u093E\u092E\u094D\u0964<br> \u0935\u091A\u0928\u0915\u0930\u0940 \u0935\u093E\u0917\u093E\u0938\u0940\u0924\u094D \u092A\u093E\u0923\u093F\u0903 \u0938\u094D\u092F\u093E\u0924\u094D\u0915\u0930\u0923\u092D\u0942\u0924 \u0906\u0926\u093E\u0928\u0947\u0965\u0967\u096F\u0965</p><p class="trans">\u015Arotr\u0101dikara\u1E47avedy\u0101\u1E25 \u015Babd\u0101dy\u0101st\u0101ni vedak\u0101nye\u1E63\u0101m\u0964<br> Vacanakar\u012B v\u0101g\u0101s\u012Bt p\u0101\u1E47i\u1E25 sy\u0101tkara\u1E47abh\u016Bta \u0101d\u0101ne\u096519\u0965</p><p>\u0423\u0448\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u0435 \u2013 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0449\u0438\u0435 \u043E\u0440\u0433\u0430\u043D\u044B, \u0438\u043C\u0438 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442\u0441\u044F \u0437\u0432\u0443\u043A \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 (\u043E\u0431\u044A\u0435\u043A\u0442\u044B). \u042F\u0437\u044B\u043A \u0435\u0441\u0442\u044C (\u043E\u0440\u0433\u0430\u043D), \u0442\u0432\u043E\u0440\u044F\u0449\u0438\u0439 \u0440\u0435\u0447\u044C. \u0420\u0443\u043A\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0440\u0433\u0430\u043D\u043E\u043C \u0445\u0432\u0430\u0442\u0430\u043D\u0438\u044F.</p></div><div class="stanza"><a href="#s20" id="s20" class="num">20</a><p class="sans">\u0917\u092E\u0928\u0935\u093F\u0938\u0930\u094D\u0917\u093E\u0928\u0928\u094D\u0926\u0924\u094D\u0930\u093F\u0924\u092F\u0947 \u092A\u093E\u0926\u093E\u0926\u093F\u0915\u0902 \u0915\u0930\u0923\u092E\u094D\u0964<br> \u0917\u0928\u094D\u0927\u0935\u0924\u0940 \u092D\u0942\u092E\u093F\u0903 \u0938\u094D\u092F\u093E\u0926\u093E\u092A\u0903 \u0938\u093E\u0902\u0938\u093F\u0926\u094D\u0927\u093F\u0915\u0926\u094D\u0930\u0935\u093E\u0938\u094D\u0924\u0947\u091C\u0903\u0965\u0968\u0966\u0965</p><p class="trans">Gamanavisarg\u0101nandatritaye p\u0101d\u0101dika\u1E41 kara\u1E47am\u0964<br> Gandhavat\u012B bh\u016Bmi\u1E25 sy\u0101d\u0101pa\u1E25 s\u0101\u1E41siddhikadrav\u0101steja\u1E25\u096520\u0965</p><p>\u0425\u043E\u0434\u044C\u0431\u0430, \u0438\u0441\u043F\u0440\u0430\u0436\u043D\u0435\u043D\u0438\u0435 \u0438 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u2013 (\u0444\u0443\u043D\u043A\u0446\u0438\u044F) \u0442\u0440\u0435\u0445 (\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445) \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043D\u043E\u0433. \u0417\u0435\u043C\u043B\u044F \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u0430 \u0437\u0430\u043F\u0430\u0445\u043E\u043C, \u0432\u043E\u0434\u0430 \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u0430 \u0442\u0435\u043A\u0443\u0447\u0435\u0441\u0442\u044C\u044E.</p></div><div class="stanza"><a href="#s21" id="s21" class="num">21</a><p class="sans">\u0909\u0937\u094D\u0923\u0938\u094D\u092A\u0930\u094D\u0936\u092E\u0930\u0942\u092A\u0938\u094D\u092A\u0930\u094D\u0936\u094B \u0935\u093E\u092F\u0941\u0930\u092E\u094D\u092C\u0930\u0902 \u0938\u0936\u092C\u094D\u0926\u092E\u094D\u0964<br> \u0937\u091F\u094D\u0924\u094D\u0930\u093F\u0902\u0936\u0924\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u092E\u092F\u0902 \u0935\u0928\u094D\u0926\u0947 \u0915\u094C\u0932\u0902 \u0915\u0941\u0932\u093E\u0924\u093F\u0917\u0902 \u0936\u092E\u094D\u092D\u0941\u092E\u094D\u0965\u0968\u0967\u0965</p><p class="trans">U\u1E63\u1E47aspar\u015Bamar\u016Bpaspar\u015Bo v\u0101yurambara\u1E41 sa\u015Babdam\u0964<br> \u1E62a\u1E6Dtri\u1E41\u015Battattvamaya\u1E41 vande kaula\u1E41 kul\u0101tiga\u1E41 \u015Bambhum\u096521\u0965</p><p>\u041E\u0433\u043E\u043D\u044C \u043D\u0430\u0434\u0435\u043B\u0435\u043D \u0442\u0435\u043F\u043B\u043E\u043C, \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435\u043C \u0438 \u0444\u043E\u0440\u043C\u043E\u0439, \u0432\u043E\u0437\u0434\u0443\u0445 (\u043D\u0430\u0434\u0435\u043B\u0435\u043D) \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435\u043C, \u0437\u0430\u043F\u0430\u0445\u043E\u043C \u0438 \u0437\u0432\u0443\u043A\u043E\u043C. \u042F \u0441\u043A\u043B\u043E\u043D\u044F\u044E\u0441\u044C \u043F\u0435\u0440\u0435\u0434 \u0428\u0430\u043C\u0431\u0445\u0443, \u041A\u0430\u0443\u043B\u043E\u0439, \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u043C \u041A\u0443\u043B\u0443, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u043C \u0438\u0437 \u0442\u0440\u0438\u0434\u0446\u0430\u0442\u0438 \u0448\u0435\u0441\u0442\u0438 \u0442\u0430\u0442\u0442\u0432.</p><p>\u0422\u0430\u043A\u043E\u0432\u0430 \xAB\u0428\u0430\u0442\u0442\u0442\u0440\u0438\u043C\u0448\u0430 \u0442\u0430\u0442\u0442\u0432\u0430 \u0441\u0430\u043D\u0434\u043E\u0445\u0430\xBB, \u0441\u043E\u0447\u0438\u043D\u0435\u043D\u043D\u0430\u044F \u0410\u043C\u0440\u0438\u0442\u0430\u043D\u0430\u043D\u0434\u0430\u043D\u0430\u0442\u0445\u043E\u0439.</p></div><ul><li><p><a href="/books/SHattrimshattattva-sandoha.pdf" target="_blank">\u041F\u0435\u0440\u0435\u0432\u043E\u0434, \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u0438 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043A \u0428\u0430\u0442\u0442\u0440\u0438\u043C\u0448\u0430\u0442\u0442\u0430\u0442\u0442\u0432\u0430-\u0441\u0430\u043D\u0434\u043E\u0445\u0435 \u0412.\u041F. \u0418\u0432\u0430\u043D\u043E\u0432\u0430 \u0432 \u0441\u043E\u0441\u0442\u0430\u0432\u0435 \xAB\u0420\u043E\u0437\u0435\u043D\u0431\u0435\u0440\u0433\u043E\u0432\u0441\u043A\u043E\u0433\u043E \u0441\u0431\u043E\u0440\u043D\u0438\u043A\u0430\xBB</a></p></li><li><p><a href="https://www.sanskrit-trikashaivism.com/ru/shattrimshattattvasandoha-1-trika-scriptures-non-dual-shaivism-of-kashmir-ru/544" class="external-link" target="_blank" rel="noopener noreferrer">\u0420\u0430\u0437\u0432\u0435\u0440\u043D\u0443\u0442\u044B\u0439 \u043F\u043E\u0441\u043B\u043E\u0432\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u1E62a\u1E6Dtri\u1E41\u015Battattvasandoha \u043D\u0430 \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u0438\u0439 \u0441 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0435\u043C R\u0101j\u0101nak\u0101nanda (17 \u0432.)</a></p></li></ul>',23),n=[p];function d(c,l,e,v,h,m){return t(),s("div",null,n)}var k=a(r,[["render",d]]);export{b as __pageData,k as default};
